1	import { useState } from "react";
2	import { useParams } from "react-router-dom";
3	import { useMarket, useMarketEvents, useAccountRisk } from "@/lib/query/hooks";
4	import { useSession } from "@/features/session/context";
5	import { StatusBadge } from "@/components/ui/StatusBadge";
6	import { ProbabilityBar } from "@/components/ui/ProbabilityBar";
7	import { LoadingPage, ErrorMessage } from "@/components/ui/Spinner";
8	import { formatCurrency, timeUntil, truncateHash, formatRelativeTime } from "@/lib/utils/format";
9	import { AssumptionProvider } from "@/features/assumptions/AssumptionContext";
10	import { AssumptionPanel } from "@/features/assumptions/AssumptionPanel";
11	import { BayesNetGraph } from "@/features/graph/BayesNetGraph";
12	import { JunctionTreePanel } from "@/features/graph/JunctionTreePanel";
13	import { DiscussionThread } from "@/features/market/DiscussionThread";
14	import { ResolveMarketPanel } from "@/features/market/ResolveMarketPanel";
15	import { EventTradePanel } from "@/features/trading/EventTradePanel";
16	import type { MarketEvent } from "@/lib/api/types";
17	
18	export default function MarketDetail() {
19	  const { marketId } = useParams<{ marketId: string }>();
20	  const { session, isConfigured } = useSession();
21	  const { data, isLoading, error } = useMarket(marketId!);
22	  const events = useMarketEvents(marketId!);
23	  const accountRisk = useAccountRisk(session.accountId);
24	
25	  if (isLoading) return <LoadingPage />;
26	  if (error) return <ErrorMessage message={error instanceof Error ? error.message : "Market not found"} />;
27	  if (!data) return null;
28	
29	  const m = data.market;
30	
31	  return (
32	    <div style={{ display: "grid", gap: "var(--space-lg)" }}>
33	      <div>
34	        <div style={{ display: "flex", gap: "var(--space-md)", alignItems: "center", marginBottom: "var(--space-sm)" }}>
35	          <h1 style={{ fontSize: "1.5rem", fontWeight: 600 }}>{m.title}</h1>
36	          <StatusBadge status={m.status} />
37	        </div>
38	        <p style={{ color: "var(--color-text-muted)", marginBottom: "var(--space-md)" }}>{m.description}</p>
39	        <div style={{ display: "flex", gap: "var(--space-lg)", fontSize: "0.85rem", color: "var(--color-text-muted)" }}>
40	          <span>Volume: {formatCurrency(m.volume)}</span>
41	          <span>Liquidity: {formatCurrency(m.liquidity)}</span>
42	          <span>Expires: {timeUntil(m.expires_at)}</span>
43	        </div>
44	      </div>
45	
46	      <ProbabilityBar outcomes={m.outcomes} marginals={m.marginals} />
47	
48	      <PositionCard marketId={m.id} accountRisk={accountRisk.data} isConfigured={isConfigured} />
49	
50	      <ResolveMarketPanel market={m} />
51	
52	      {m.status === "active" && (
53	        <AssumptionProvider>
54	          <AssumptionPanel market={m} />
55	        </AssumptionProvider>
56	      )}
57	
58	      <EventTradePanel market={m} />
59	
60	      <DiscussionThread market={m} />
61	
62	      <BayesNetGraph focusMarketId={m.id} />
63	
64	      {/* Event Journal */}
65	      <div>
66	        <h2 style={{ fontSize: "1.1rem", fontWeight: 600, marginBottom: "var(--space-sm)" }}>Event Journal</h2>
67	        {events.isLoading && <LoadingPage />}
68	        {events.data && events.data.events.length === 0 && (
69	          <span style={{ color: "var(--color-text-muted)", fontSize: "0.85rem" }}>No events yet.</span>
70	        )}
71	        {events.data && events.data.events.length > 0 && (
72	          <div style={{ borderRadius: "var(--radius-md)", border: "1px solid var(--color-border)", overflow: "hidden" }}>
73	            <table style={{ width: "100%", borderCollapse: "collapse", fontSize: "0.8rem" }}>
74	              <thead>
75	                <tr style={{ background: "var(--color-bg-hover)" }}>
76	                  <th style={thStyle}>Seq</th>
77	                  <th style={thStyle}>Type</th>
78	                  <th style={thStyle}>Hash</th>
79	                  <th style={thStyle}>Time</th>
80	                </tr>
81	              </thead>
82	              <tbody>
83	                {events.data.events.map((e) => (
84	                  <EventRow key={e.eventId} event={e} />
85	                ))}
86	              </tbody>
87	            </table>
88	          </div>
89	        )}
90	      </div>
91	
92	      <JunctionTreePanel marketId={m.id} />
93	    </div>
94	  );
95	}
96	
97	function PositionCard({
98	  marketId,
99	  accountRisk,
100	  isConfigured,
101	}: {
102	  marketId: string;
103	  accountRisk: import("@/lib/api/types").AccountRiskResponse | undefined;
104	  isConfigured: boolean;
105	}) {
106	  if (!isConfigured || !accountRisk) return null;
107	
108	  const marketRisk = accountRisk.account.risk.minAssets.markets.find(
109	    (mr) => mr.marketId === marketId,
110	  );
111	
112	  if (!marketRisk) return null;
113	
114	  const utilColor = marketRisk.utilization > 0.8
115	    ? "var(--color-danger)"
116	    : marketRisk.utilization > 0.5
117	      ? "var(--color-warning, orange)"
118	      : "var(--color-text)";
119	
120	  return (
121	    <div style={positionCardStyle}>
122	      <div style={{ fontSize: "0.8rem", fontWeight: 600, marginBottom: "var(--space-xs)" }}>
123	        Your Position
124	      </div>
125	      <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: "var(--space-sm)", fontSize: "0.8rem" }}>
126	        <div>
127	          <div style={{ color: "var(--color-text-muted)", fontSize: "0.7rem" }}>Min Asset</div>
128	          <div style={{ fontFamily: "var(--font-mono)", fontWeight: 600 }}>{marketRisk.minAsset.toFixed(2)}</div>
129	        </div>
130	        <div>
131	          <div style={{ color: "var(--color-text-muted)", fontSize: "0.7rem" }}>Utilization</div>
132	          <div style={{ fontFamily: "var(--font-mono)", fontWeight: 600, color: utilColor }}>
133	            {(marketRisk.utilization * 100).toFixed(1)}%
134	          </div>
135	        </div>
136	        <div>
137	          <div style={{ color: "var(--color-text-muted)", fontSize: "0.7rem" }}>Trades</div>
138	          <div style={{ fontFamily: "var(--font-mono)", fontWeight: 600 }}>{marketRisk.commandCount}</div>
139	        </div>
140	      </div>
141	    </div>
142	  );
143	}
144	
145	function EventRow({ event }: { event: MarketEvent }) {
146	  const [expanded, setExpanded] = useState(false);
147	  const hasPayload = Object.keys(event.payload).length > 0;
148	
149	  return (
150	    <>
151	      <tr
152	        onClick={() => hasPayload && setExpanded(!expanded)}
153	        style={{ borderTop: "1px solid var(--color-border)", cursor: hasPayload ? "pointer" : "default" }}
154	      >
155	        <td style={tdStyle}>{event.seq}</td>
156	        <td style={tdStyle}>
157	          {hasPayload && <span style={{ marginRight: 4, fontSize: "0.65rem" }}>{expanded ? "\u25BC" : "\u25B6"}</span>}
158	          {event.type}
159	        </td>
160	        <td style={{ ...tdStyle, fontFamily: "var(--font-mono)", fontSize: "0.75rem" }}>
161	          {truncateHash(event.eventHash)}
162	        </td>
163	        <td style={tdStyle}>{formatRelativeTime(event.timestamp)}</td>
164	      </tr>
165	      {expanded && (
166	        <tr>
167	          <td colSpan={4} style={{ padding: "0 12px 8px 12px" }}>
168	            <pre style={payloadStyle}>{JSON.stringify(event.payload, null, 2)}</pre>
169	          </td>
170	        </tr>
171	      )}
172	    </>
173	  );
174	}
175	
176	const thStyle: React.CSSProperties = { textAlign: "left", padding: "6px 12px", fontWeight: 500 };
177	const tdStyle: React.CSSProperties = { padding: "6px 12px" };
178	
179	const positionCardStyle: React.CSSProperties = {
180	  padding: "var(--space-sm) var(--space-md)",
181	  borderRadius: "var(--radius-md)",
182	  border: "1px solid var(--color-border)",
183	  background: "var(--color-bg-surface)",
184	};
185	
186	const payloadStyle: React.CSSProperties = {
187	  margin: 0,
188	  padding: "var(--space-sm)",
189	  borderRadius: "var(--radius-sm)",
190	  background: "var(--color-bg)",
191	  border: "1px solid var(--color-border)",
192	  fontSize: "0.7rem",
193	  fontFamily: "var(--font-mono)",
194	  overflow: "auto",
195	  maxHeight: 200,
196	};
