186	  borderRadius: "var(--radius-sm)",
187	  border: "1px solid var(--color-border)",
188	  background: "transparent",
189	  color: "var(--color-text-muted)",
190	  fontSize: "0.8rem",
191	  cursor: "pointer",
192	};
